import sys

class Solution:
    def bellmanFord(self, edges: list[list[int]], V: int, S: int) -> list[int]:
        dist = [100000000] * V
        dist[S] = 0

        for _ in range(V - 1):
            for u, v, w in edges:
                if dist[u] != 100000000 and dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w

        for u, v, w in edges:
            if dist[u] != 100000000 and dist[u] + w < dist[v]:
                return [-1]

        return dist

