#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> bellmanFord(vector<vector<int>>& edges, int V, int S) {
        vector<int> dist(V, 100000000);
        dist[S] = 0;

        for (int i = 0; i < V - 1; i++) {
            for (auto& edge : edges) {
                int u = edge[0], v = edge[1], w = edge[2];
                if (dist[u] != 100000000 && dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                }
            }
        }

        for (auto& edge : edges) {
            int u = edge[0], v = edge[1], w = edge[2];
            if (dist[u] != 100000000 && dist[u] + w < dist[v]) {
                return {-1};
            }
        }

        return dist;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(3));
    for (int i = 0; i < E; i++) cin >> edges[i][0] >> edges[i][1] >> edges[i][2];
    int S;
    if (!(cin >> S)) return 0;
    Solution sol;
    vector<int> ans = sol.bellmanFord(edges, V, S);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
